//! pxr.Vt — Value Types bindings.
//!
//! Implements drop-in replacement for `pxr.Vt` from C++ OpenUSD:
//! - `Value` / `_ValueWrapper` — type-erased value container with explicit factory methods
//! - `VtArray<T>` — 30+ typed array classes generated by macro
//! - `Dictionary` — bidirectional Python dict ↔ VtDictionary conversion

use pyo3::exceptions::{PyIndexError, PyTypeError, PyValueError};
use pyo3::prelude::*;
use pyo3::types::{PyDict, PyList, PySlice};

use usd_vt::{Array, Dictionary, Value};

// ============================================================================
// Helpers
// ============================================================================

/// Normalise a Python signed index into [0, len), returning IndexError on OOB.
fn norm_idx(i: isize, len: usize) -> PyResult<usize> {
    let len_i = len as isize;
    let idx = if i < 0 { len_i + i } else { i };
    if idx < 0 || idx >= len_i {
        Err(PyIndexError::new_err(format!(
            "index {i} out of range for array of length {len}"
        )))
    } else {
        Ok(idx as usize)
    }
}

// ============================================================================
// VtValue / _ValueWrapper
// ============================================================================

/// Explicit typed wrapper over `Value` — mirrors C++ `Vt._ValueWrapper`.
///
/// Python code can request an exact wire type via static factory methods
/// (`Bool`, `Int`, `Float`, etc.) rather than relying on Python-type inference.
#[pyclass(name = "_ValueWrapper", module = "pxr.Vt")]
#[derive(Clone)]
pub struct PyValue {
    inner: Value,
    /// Human-readable type tag for repr (e.g. "int", "double").
    tag: &'static str,
}

#[pymethods]
impl PyValue {
    // -- Factories -----------------------------------------------------------

    /// Create a `Value` holding a Python object (auto-convert).
    ///
    /// Conversion rules mirror C++ wrapValue:
    ///   None      → empty
    ///   bool      → bool
    ///   int       → i32
    ///   float     → f64
    ///   str/bytes → String
    #[new]
    #[pyo3(signature = (obj = None))]
    fn new(obj: Option<&Bound<'_, PyAny>>) -> PyResult<Self> {
        let Some(obj) = obj else {
            return Ok(Self { inner: Value::empty(), tag: "empty" });
        };
        // bool before int — Python bool is a subclass of int
        if let Ok(b) = obj.extract::<bool>() {
            return Ok(Self { inner: Value::new(b), tag: "bool" });
        }
        if let Ok(i) = obj.extract::<i64>() {
            // Range-fit: prefer i32 for small values (matches C++)
            if i >= i64::from(i32::MIN) && i <= i64::from(i32::MAX) {
                return Ok(Self { inner: Value::new(i as i32), tag: "int" });
            }
            return Ok(Self { inner: Value::new(i), tag: "int64" });
        }
        if let Ok(f) = obj.extract::<f64>() {
            return Ok(Self { inner: Value::from_f64(f), tag: "double" });
        }
        if let Ok(s) = obj.extract::<String>() {
            return Ok(Self { inner: Value::new(s), tag: "string" });
        }
        // Fall back to empty — don't panic on unknown objects
        Ok(Self { inner: Value::empty(), tag: "unknown" })
    }

    // -- Explicit typed factories --------------------------------------------

    /// `Value` holding a `bool`.
    #[staticmethod]
    #[pyo3(name = "Bool")]
    fn mk_bool(v: bool) -> Self {
        Self { inner: Value::new(v), tag: "bool" }
    }

    /// `Value` holding a `u8`.
    #[staticmethod]
    #[pyo3(name = "UChar")]
    fn mk_uchar(v: u8) -> Self {
        Self { inner: Value::new(v), tag: "uchar" }
    }

    /// `Value` holding an `i16`.
    #[staticmethod]
    #[pyo3(name = "Short")]
    fn mk_short(v: i16) -> Self {
        Self { inner: Value::new(v), tag: "short" }
    }

    /// `Value` holding a `u16`.
    #[staticmethod]
    #[pyo3(name = "UShort")]
    fn mk_ushort(v: u16) -> Self {
        Self { inner: Value::new(v), tag: "ushort" }
    }

    /// `Value` holding an `i32`.
    #[staticmethod]
    #[pyo3(name = "Int")]
    fn mk_int(v: i32) -> Self {
        Self { inner: Value::new(v), tag: "int" }
    }

    /// `Value` holding a `u32`.
    #[staticmethod]
    #[pyo3(name = "UInt")]
    fn mk_uint(v: u32) -> Self {
        Self { inner: Value::new(v), tag: "uint" }
    }

    /// `Value` holding an `i64`.
    #[staticmethod]
    #[pyo3(name = "Long")]
    fn mk_long(v: i64) -> Self {
        Self { inner: Value::new(v), tag: "long" }
    }

    /// Alias for `Long`.
    #[staticmethod]
    #[pyo3(name = "Int64")]
    fn mk_int64(v: i64) -> Self {
        Self { inner: Value::new(v), tag: "int64" }
    }

    /// `Value` holding a `u64`.
    #[staticmethod]
    #[pyo3(name = "ULong")]
    fn mk_ulong(v: u64) -> Self {
        Self { inner: Value::new(v), tag: "ulong" }
    }

    /// Alias for `ULong`.
    #[staticmethod]
    #[pyo3(name = "UInt64")]
    fn mk_uint64(v: u64) -> Self {
        Self { inner: Value::new(v), tag: "uint64" }
    }

    /// `Value` holding an `f32`.
    #[staticmethod]
    #[pyo3(name = "Float")]
    fn mk_float(v: f32) -> Self {
        Self { inner: Value::from_f32(v), tag: "float" }
    }

    /// `Value` holding an `f64`.
    #[staticmethod]
    #[pyo3(name = "Double")]
    fn mk_double(v: f64) -> Self {
        Self { inner: Value::from_f64(v), tag: "double" }
    }

    /// `Value` holding a half-precision float (stored as `f32` proxy).
    #[staticmethod]
    #[pyo3(name = "Half")]
    fn mk_half(v: f32) -> Self {
        // half::f16 not directly usable via pyo3; store as f32 proxy
        Self { inner: Value::from_f32(v), tag: "half" }
    }

    /// `Value` holding a `TfToken` (interned string).
    #[staticmethod]
    #[pyo3(name = "Token")]
    fn mk_token(v: &str) -> Self {
        let tok = usd_tf::Token::new(v);
        Self { inner: Value::new(tok), tag: "token" }
    }

    // -- Inspection ----------------------------------------------------------

    /// Returns `True` if this value is empty (holds no data).
    #[pyo3(name = "IsEmpty")]
    fn is_empty(&self) -> bool {
        self.inner.is_empty()
    }

    // -- Dunder methods ------------------------------------------------------

    fn __eq__(&self, other: &Self) -> bool {
        self.inner == other.inner
    }

    fn __ne__(&self, other: &Self) -> bool {
        self.inner != other.inner
    }

    fn __str__(&self) -> String {
        format!("{}", ValueDisplay(&self.inner))
    }

    fn __repr__(&self) -> String {
        format!("Vt._ValueWrapper({}: {})", self.tag, ValueDisplay(&self.inner))
    }
}

/// Lightweight Display adapter so we can format `Value` without allocating a new type.
struct ValueDisplay<'a>(&'a Value);

impl std::fmt::Display for ValueDisplay<'_> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        if self.0.is_empty() {
            return write!(f, "<empty>");
        }
        // Try common types in priority order
        if let Some(b) = self.0.get::<bool>() {
            return write!(f, "{b}");
        }
        if let Some(i) = self.0.get::<i32>() {
            return write!(f, "{i}");
        }
        if let Some(i) = self.0.get::<i64>() {
            return write!(f, "{i}");
        }
        if let Some(u) = self.0.get::<u64>() {
            return write!(f, "{u}");
        }
        if let Some(x) = self.0.get::<f64>() {
            return write!(f, "{x}");
        }
        if let Some(x) = self.0.get::<f32>() {
            return write!(f, "{x}");
        }
        if let Some(s) = self.0.get::<String>() {
            return write!(f, "{s}");
        }
        if let Some(t) = self.0.get::<usd_tf::Token>() {
            return write!(f, "{t}");
        }
        write!(f, "<value>")
    }
}

// ============================================================================
// VtArray macro — generates one Python class per element type
// ============================================================================
//
// Design rationale: the C++ wrapArray.h template generates identical APIs for
// 80+ instantiations. We replicate this with a single Rust `macro_rules!` that
// produces a struct + `#[pymethods]` block per type combination.
//
// Each generated class:
//   - Wraps `Array<$elem>` from usd-vt
//   - Exposes `__len__`, `__getitem__`, `__setitem__`, `__iter__`, `__repr__`,
//     `__str__`, `__eq__`, `__ne__`
//   - Conditionally exposes arithmetic operators via separate trait arms
//
// The `$elem_display` closure converts an element to a Python-legible string.

macro_rules! vt_array {
    // Scalar numeric arrays — supports full arithmetic
    (
        numeric,
        name    = $py_name:literal,
        module  = $py_mod:literal,
        rust    = $rust_name:ident,
        elem    = $elem:ty,
        fmt     = $fmt_fn:expr,
        iter_ty = $iter_ty:ident
    ) => {
        #[pyclass(name = $py_name, module = $py_mod)]
        #[derive(Clone)]
        pub struct $rust_name {
            inner: Array<$elem>,
        }

        #[pymethods]
        impl $rust_name {
            // Constructors -------------------------------------------------------

            #[new]
            #[pyo3(signature = (arg = None))]
            fn new(arg: Option<&Bound<'_, PyAny>>) -> PyResult<Self> {
                build_array::<$elem>(arg, <$elem as Default>::default)
                    .map(|inner| Self { inner })
            }

            // Length / indexing --------------------------------------------------

            fn __len__(&self) -> usize {
                self.inner.len()
            }

            fn __getitem__(&self, py: Python<'_>, key: &Bound<'_, PyAny>) -> PyResult<PyObject> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    // SAFETY: idx is bounds-checked above
                    Ok(($fmt_fn)(self.inner.as_slice()[idx]).into_py(py))
                } else if let Ok(slice) = key.downcast::<PySlice>() {
                    let indices = slice.indices(self.inner.len() as std::ffi::c_long)?;
                    let list = PyList::empty(py);
                    let mut idx = indices.start;
                    while (indices.step > 0 && idx < indices.stop)
                        || (indices.step < 0 && idx > indices.stop)
                    {
                        list.append(($fmt_fn)(self.inner.as_slice()[idx as usize]).into_py(py))?;
                        idx += indices.step;
                    }
                    Ok(list.into())
                } else {
                    Err(PyTypeError::new_err("index must be int or slice"))
                }
            }

            fn __setitem__(
                &mut self,
                key: &Bound<'_, PyAny>,
                value: &Bound<'_, PyAny>,
            ) -> PyResult<()> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    let elem: $elem = value.extract()?;
                    self.inner.make_unique();
                    // SAFETY: idx bounds-checked; make_unique ensures exclusive ownership
                    self.inner.as_mut_slice()[idx] = elem;
                    Ok(())
                } else if let Ok(slice) = key.downcast::<PySlice>() {
                    let indices = slice.indices(self.inner.len() as std::ffi::c_long)?;
                    // Collect new values first
                    let list: Vec<$elem> = value.extract()?;
                    self.inner.make_unique();
                    let data = self.inner.as_mut_slice();
                    let mut idx = indices.start as usize;
                    for elem in list {
                        if idx >= data.len() {
                            break;
                        }
                        data[idx] = elem;
                        idx = (idx as isize + indices.step) as usize;
                    }
                    Ok(())
                } else {
                    Err(PyTypeError::new_err("index must be int or slice"))
                }
            }

            // Iteration ----------------------------------------------------------

            fn __iter__(slf: PyRef<'_, Self>) -> PyResult<Py<$iter_ty>> {
                let iter = <$iter_ty>::new_from_data(slf.inner.as_slice().to_vec());
                Py::new(slf.py(), iter)
            }

            // Comparison ---------------------------------------------------------

            fn __eq__(&self, other: &Self) -> bool {
                self.inner.as_slice() == other.inner.as_slice()
            }

            fn __ne__(&self, other: &Self) -> bool {
                self.inner.as_slice() != other.inner.as_slice()
            }

            // String representation ----------------------------------------------

            fn __repr__(&self) -> String {
                let type_name = $py_name;
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|x| format!("{}", ($fmt_fn)(*x)))
                    .collect();
                format!("Vt.{}([{}])", type_name, elems.join(", "))
            }

            fn __str__(&self) -> String {
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|x| format!("{}", ($fmt_fn)(*x)))
                    .collect();
                format!("[{}]", elems.join(", "))
            }

            // Arithmetic ---------------------------------------------------------

            fn __add__(&self, other: &Self) -> Self {
                let data: Vec<$elem> = self.inner.as_slice()
                    .iter()
                    .zip(other.inner.as_slice().iter())
                    .map(|(a, b)| *a + *b)
                    .collect();
                Self { inner: Array::from(data) }
            }

            fn __radd__(&self, other: &Self) -> Self {
                self.__add__(other)
            }

            fn __sub__(&self, other: &Self) -> Self {
                let data: Vec<$elem> = self.inner.as_slice()
                    .iter()
                    .zip(other.inner.as_slice().iter())
                    .map(|(a, b)| *a - *b)
                    .collect();
                Self { inner: Array::from(data) }
            }

            fn __rsub__(&self, other: &Self) -> Self {
                other.__sub__(self)
            }

            fn __neg__(&self) -> Self {
                let data: Vec<$elem> = self.inner.as_slice()
                    .iter()
                    .map(|a| -(*a))
                    .collect();
                Self { inner: Array::from(data) }
            }

            fn __mul__(&self, scalar: f64) -> Self {
                let s = scalar as $elem;
                let data: Vec<$elem> = self.inner.as_slice()
                    .iter()
                    .map(|a| *a * s)
                    .collect();
                Self { inner: Array::from(data) }
            }

            fn __rmul__(&self, scalar: f64) -> Self {
                self.__mul__(scalar)
            }

            fn __truediv__(&self, scalar: f64) -> PyResult<Self> {
                if scalar == 0.0 {
                    return Err(pyo3::exceptions::PyZeroDivisionError::new_err(
                        "division by zero",
                    ));
                }
                let s = scalar as $elem;
                let data: Vec<$elem> = self.inner.as_slice()
                    .iter()
                    .map(|a| *a / s)
                    .collect();
                Ok(Self { inner: Array::from(data) })
            }
        }
    };

    // No-arithmetic arrays — only comparison and indexing (bool, token, etc.)
    (
        no_arith,
        name    = $py_name:literal,
        module  = $py_mod:literal,
        rust    = $rust_name:ident,
        elem    = $elem:ty,
        fmt     = $fmt_fn:expr,
        iter_ty = $iter_ty:ident
    ) => {
        #[pyclass(name = $py_name, module = $py_mod)]
        #[derive(Clone)]
        pub struct $rust_name {
            inner: Array<$elem>,
        }

        #[pymethods]
        impl $rust_name {
            #[new]
            #[pyo3(signature = (arg = None))]
            fn new(arg: Option<&Bound<'_, PyAny>>) -> PyResult<Self> {
                build_array::<$elem>(arg, <$elem as Default>::default)
                    .map(|inner| Self { inner })
            }

            fn __len__(&self) -> usize { self.inner.len() }

            fn __getitem__(&self, py: Python<'_>, key: &Bound<'_, PyAny>) -> PyResult<PyObject> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    Ok(($fmt_fn)(self.inner.as_slice()[idx]).into_py(py))
                } else if let Ok(slice) = key.downcast::<PySlice>() {
                    let indices = slice.indices(self.inner.len() as std::ffi::c_long)?;
                    let list = PyList::empty(py);
                    let mut idx = indices.start;
                    while (indices.step > 0 && idx < indices.stop)
                        || (indices.step < 0 && idx > indices.stop)
                    {
                        list.append(($fmt_fn)(self.inner.as_slice()[idx as usize]).into_py(py))?;
                        idx += indices.step;
                    }
                    Ok(list.into())
                } else {
                    Err(PyTypeError::new_err("index must be int or slice"))
                }
            }

            fn __setitem__(
                &mut self,
                key: &Bound<'_, PyAny>,
                value: &Bound<'_, PyAny>,
            ) -> PyResult<()> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    let elem: $elem = value.extract()?;
                    self.inner.make_unique();
                    self.inner.as_mut_slice()[idx] = elem;
                    Ok(())
                } else {
                    Err(PyTypeError::new_err("index must be int"))
                }
            }

            fn __iter__(slf: PyRef<'_, Self>) -> PyResult<Py<$iter_ty>> {
                let iter = <$iter_ty>::new_from_data(slf.inner.as_slice().to_vec());
                Py::new(slf.py(), iter)
            }

            fn __eq__(&self, other: &Self) -> bool {
                self.inner.as_slice() == other.inner.as_slice()
            }

            fn __ne__(&self, other: &Self) -> bool {
                self.inner.as_slice() != other.inner.as_slice()
            }

            fn __repr__(&self) -> String {
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|x| format!("{}", ($fmt_fn)(*x)))
                    .collect();
                format!("Vt.{}([{}])", $py_name, elems.join(", "))
            }

            fn __str__(&self) -> String {
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|x| format!("{}", ($fmt_fn)(*x)))
                    .collect();
                format!("[{}]", elems.join(", "))
            }
        }
    };

    // String-like arrays — only __add__ (concatenation), no neg/mul/div
    (
        string,
        name   = $py_name:literal,
        module = $py_mod:literal,
        rust   = $rust_name:ident,
        elem   = $elem:ty
    ) => {
        #[pyclass(name = $py_name, module = $py_mod)]
        #[derive(Clone)]
        pub struct $rust_name {
            inner: Array<$elem>,
        }

        #[pymethods]
        impl $rust_name {
            #[new]
            #[pyo3(signature = (arg = None))]
            fn new(arg: Option<&Bound<'_, PyAny>>) -> PyResult<Self> {
                build_array_clone::<$elem>(arg).map(|inner| Self { inner })
            }

            fn __len__(&self) -> usize { self.inner.len() }

            fn __getitem__(&self, py: Python<'_>, key: &Bound<'_, PyAny>) -> PyResult<PyObject> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    Ok(self.inner.as_slice()[idx].clone().into_py(py))
                } else if let Ok(slice) = key.downcast::<PySlice>() {
                    let indices = slice.indices(self.inner.len() as std::ffi::c_long)?;
                    let list = PyList::empty(py);
                    let mut idx = indices.start;
                    while (indices.step > 0 && idx < indices.stop)
                        || (indices.step < 0 && idx > indices.stop)
                    {
                        list.append(self.inner.as_slice()[idx as usize].clone().into_py(py))?;
                        idx += indices.step;
                    }
                    Ok(list.into())
                } else {
                    Err(PyTypeError::new_err("index must be int or slice"))
                }
            }

            fn __setitem__(
                &mut self,
                key: &Bound<'_, PyAny>,
                value: &Bound<'_, PyAny>,
            ) -> PyResult<()> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    let elem: $elem = value.extract()?;
                    self.inner.make_unique();
                    self.inner.as_mut_slice()[idx] = elem;
                    Ok(())
                } else {
                    Err(PyTypeError::new_err("index must be int"))
                }
            }

            fn __iter__(slf: PyRef<'_, Self>) -> PyResult<Py<VtStringIter>> {
                let iter = VtStringIter {
                    data: slf.inner.as_slice()
                        .iter()
                        .map(|s| format!("{s}"))
                        .collect(),
                    pos: 0,
                };
                Py::new(slf.py(), iter)
            }

            fn __eq__(&self, other: &Self) -> bool {
                self.inner.as_slice() == other.inner.as_slice()
            }

            fn __ne__(&self, other: &Self) -> bool {
                self.inner.as_slice() != other.inner.as_slice()
            }

            fn __repr__(&self) -> String {
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|s| format!("{s:?}"))
                    .collect();
                format!("Vt.{}([{}])", $py_name, elems.join(", "))
            }

            fn __str__(&self) -> String {
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|s| format!("{s}"))
                    .collect();
                format!("[{}]", elems.join(", "))
            }

            fn __add__(&self, other: &Self) -> Self {
                let mut data = self.inner.as_slice().to_vec();
                data.extend_from_slice(other.inner.as_slice());
                Self { inner: Array::from(data) }
            }
        }
    };

    // Vector/matrix arrays — add, sub, neg, double-mul; no div
    (
        vec,
        name        = $py_name:literal,
        module      = $py_mod:literal,
        rust        = $rust_name:ident,
        elem        = $elem:ty,
        py_elem     = $py_elem:ty,
        from_py     = $from_py:expr,
        to_py       = $to_py:expr
    ) => {
        #[pyclass(name = $py_name, module = $py_mod)]
        #[derive(Clone)]
        pub struct $rust_name {
            inner: Array<$elem>,
        }

        #[pymethods]
        impl $rust_name {
            #[new]
            #[pyo3(signature = (arg = None))]
            fn new(arg: Option<&Bound<'_, PyAny>>) -> PyResult<Self> {
                let inner = build_array_mapped::<$elem, $py_elem>(arg, $from_py)?;
                Ok(Self { inner })
            }

            fn __len__(&self) -> usize { self.inner.len() }

            fn __getitem__(&self, py: Python<'_>, key: &Bound<'_, PyAny>) -> PyResult<PyObject> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    Ok(($to_py)(self.inner.as_slice()[idx].clone()).into_py(py))
                } else if let Ok(slice) = key.downcast::<PySlice>() {
                    let indices = slice.indices(self.inner.len() as std::ffi::c_long)?;
                    let list = PyList::empty(py);
                    let mut idx = indices.start;
                    while (indices.step > 0 && idx < indices.stop)
                        || (indices.step < 0 && idx > indices.stop)
                    {
                        list.append(($to_py)(self.inner.as_slice()[idx as usize].clone()).into_py(py))?;
                        idx += indices.step;
                    }
                    Ok(list.into())
                } else {
                    Err(PyTypeError::new_err("index must be int or slice"))
                }
            }

            fn __setitem__(
                &mut self,
                key: &Bound<'_, PyAny>,
                value: &Bound<'_, PyAny>,
            ) -> PyResult<()> {
                if let Ok(i) = key.extract::<isize>() {
                    let idx = norm_idx(i, self.inner.len())?;
                    let py_val: $py_elem = value.extract()?;
                    self.inner.make_unique();
                    self.inner.as_mut_slice()[idx] = ($from_py)(py_val);
                    Ok(())
                } else {
                    Err(PyTypeError::new_err("index must be int"))
                }
            }

            fn __iter__(slf: PyRef<'_, Self>) -> PyResult<Py<VtStringIter>> {
                let data: Vec<String> = slf.inner.as_slice()
                    .iter()
                    .map(|v| format!("{:?}", ($to_py)(v.clone())))
                    .collect();
                Py::new(slf.py(), VtStringIter { data, pos: 0 })
            }

            fn __eq__(&self, other: &Self) -> bool {
                self.inner.as_slice() == other.inner.as_slice()
            }

            fn __ne__(&self, other: &Self) -> bool {
                self.inner.as_slice() != other.inner.as_slice()
            }

            fn __repr__(&self) -> String {
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|v| format!("{:?}", ($to_py)(v.clone())))
                    .collect();
                format!("Vt.{}([{}])", $py_name, elems.join(", "))
            }

            fn __str__(&self) -> String {
                let elems: Vec<String> = self.inner.as_slice()
                    .iter()
                    .map(|v| format!("{:?}", ($to_py)(v.clone())))
                    .collect();
                format!("[{}]", elems.join(", "))
            }
        }
    };
}

// ============================================================================
// Generic array construction helpers
// ============================================================================

/// Build `Array<T>` from `None` (empty), `int` (sized), or sequence.
/// Used for Copy+Default scalars that are directly extractable from Python.
fn build_array<T>(
    arg: Option<&Bound<'_, PyAny>>,
    default: fn() -> T,
) -> PyResult<Array<T>>
where
    T: Clone + Send + Sync + for<'py> FromPyObject<'py> + 'static,
{
    let Some(obj) = arg else {
        return Ok(Array::new());
    };

    // Single usize → preallocate with default fill
    if let Ok(n) = obj.extract::<usize>() {
        return Ok(Array::from_elem(default(), n));
    }

    // Sequence of values
    let list: Vec<T> = obj
        .extract()
        .map_err(|_| PyValueError::new_err("expected int size or sequence"))?;
    Ok(Array::from(list))
}

/// Same as `build_array` but for Clone types (String, Token).
fn build_array_clone<T>(arg: Option<&Bound<'_, PyAny>>) -> PyResult<Array<T>>
where
    T: Clone + Send + Sync + Default + for<'py> FromPyObject<'py> + 'static,
{
    let Some(obj) = arg else {
        return Ok(Array::new());
    };
    if let Ok(n) = obj.extract::<usize>() {
        return Ok(Array::from_elem(T::default(), n));
    }
    let list: Vec<T> = obj
        .extract()
        .map_err(|_| PyValueError::new_err("expected int size or sequence"))?;
    Ok(Array::from(list))
}

/// Build `Array<T>` from a Python sequence of `PyElem`, mapping via `from_py`.
fn build_array_mapped<T, PyElem>(
    arg: Option<&Bound<'_, PyAny>>,
    from_py: fn(PyElem) -> T,
) -> PyResult<Array<T>>
where
    T: Clone + Send + Sync + Default + 'static,
    PyElem: for<'py> FromPyObject<'py>,
{
    let Some(obj) = arg else {
        return Ok(Array::new());
    };
    if let Ok(n) = obj.extract::<usize>() {
        return Ok(Array::from_elem(T::default(), n));
    }
    let list: Vec<PyElem> = obj
        .extract()
        .map_err(|_| PyValueError::new_err("expected int size or sequence"))?;
    let mapped: Vec<T> = list.into_iter().map(from_py).collect();
    Ok(Array::from(mapped))
}

// ============================================================================
// Iterator helpers
// ============================================================================
//
// PyO3 does not support generic #[pyclass]. We define one concrete iterator
// per scalar type via macro, plus a string-based iterator for complex types.

macro_rules! define_scalar_iter {
    ($name:ident, $elem:ty) => {
        #[pyclass]
        pub struct $name {
            data: Vec<$elem>,
            pos: usize,
        }

        impl $name {
            /// Construct from a collected vec of elements.
            pub fn new_from_data(data: Vec<$elem>) -> Self {
                Self { data, pos: 0 }
            }
        }

        #[pymethods]
        impl $name {
            fn __iter__(slf: PyRef<'_, Self>) -> PyRef<'_, Self> {
                slf
            }

            fn __next__(mut slf: PyRefMut<'_, Self>) -> Option<$elem> {
                if slf.pos < slf.data.len() {
                    let v = slf.data[slf.pos];
                    slf.pos += 1;
                    Some(v)
                } else {
                    None
                }
            }
        }
    };
}

define_scalar_iter!(VtBoolIter,   bool);
define_scalar_iter!(VtI32Iter,    i32);
define_scalar_iter!(VtU32Iter,    u32);
define_scalar_iter!(VtI64Iter,    i64);
define_scalar_iter!(VtU64Iter,    u64);
define_scalar_iter!(VtI8Iter,     i8);
define_scalar_iter!(VtU8Iter,     u8);
define_scalar_iter!(VtI16Iter,    i16);
define_scalar_iter!(VtU16Iter,    u16);
define_scalar_iter!(VtF32Iter,    f32);
define_scalar_iter!(VtF64Iter,    f64);

/// String-based iterator (covers String, Token, and struct types rendered as strings).
#[pyclass]
pub struct VtStringIter {
    data: Vec<String>,
    pos: usize,
}

#[pymethods]
impl VtStringIter {
    fn __iter__(slf: PyRef<'_, Self>) -> PyRef<'_, Self> {
        slf
    }

    fn __next__(mut slf: PyRefMut<'_, Self>) -> Option<String> {
        if slf.pos < slf.data.len() {
            let s = slf.data[slf.pos].clone();
            slf.pos += 1;
            Some(s)
        } else {
            None
        }
    }
}

