// TokenArray wraps usd_tf::Token; we expose as String at the Python boundary
// since Token is an interned string with the same external behaviour.
#[pyclass(name = "TokenArray", module = "pxr.Vt")]
#[derive(Clone)]
pub struct PyTokenArray {
    inner: Array<usd_tf::Token>,
}

#[pymethods]
impl PyTokenArray {
    #[new]
    #[pyo3(signature = (arg = None))]
    fn new(arg: Option<&Bound<'_, PyAny>>) -> PyResult<Self> {
        let Some(obj) = arg else {
            return Ok(Self { inner: Array::new() });
        };
        if let Ok(n) = obj.extract::<usize>() {
            let empty = usd_tf::Token::new("");
            return Ok(Self { inner: Array::from_elem(empty, n) });
        }
        let strings: Vec<String> = obj
            .extract()
            .map_err(|_| PyValueError::new_err("expected int size or sequence of str"))?;
        let tokens: Vec<usd_tf::Token> = strings.iter().map(|s| usd_tf::Token::new(s)).collect();
        Ok(Self { inner: Array::from(tokens) })
    }

    fn __len__(&self) -> usize { self.inner.len() }

    fn __getitem__(&self, py: Python<'_>, key: &Bound<'_, PyAny>) -> PyResult<PyObject> {
        if let Ok(i) = key.extract::<isize>() {
            let idx = norm_idx(i, self.inner.len())?;
            Ok(self.inner.as_slice()[idx].to_string().into_py(py))
        } else if let Ok(slice) = key.downcast::<PySlice>() {
            let indices = slice.indices(self.inner.len() as std::ffi::c_long)?;
            let list = PyList::empty(py);
            let mut idx = indices.start;
            while (indices.step > 0 && idx < indices.stop)
                || (indices.step < 0 && idx > indices.stop)
            {
                list.append(self.inner.as_slice()[idx as usize].to_string().into_py(py))?;
                idx += indices.step;
            }
            Ok(list.into())
        } else {
            Err(PyTypeError::new_err("index must be int or slice"))
        }
    }

    fn __setitem__(&mut self, key: &Bound<'_, PyAny>, value: &Bound<'_, PyAny>) -> PyResult<()> {
        if let Ok(i) = key.extract::<isize>() {
            let idx = norm_idx(i, self.inner.len())?;
            let s: String = value.extract()?;
            self.inner.make_unique();
            self.inner.as_mut_slice()[idx] = usd_tf::Token::new(&s);
            Ok(())
        } else {
            Err(PyTypeError::new_err("index must be int"))
        }
    }

    fn __iter__(slf: PyRef<'_, Self>) -> PyResult<Py<VtStringIter>> {
        let data: Vec<String> = slf.inner.as_slice()
            .iter()
            .map(|t| t.to_string())
            .collect();
        Py::new(slf.py(), VtStringIter { data, pos: 0 })
    }

    fn __eq__(&self, other: &Self) -> bool {
        self.inner.as_slice() == other.inner.as_slice()
    }

    fn __ne__(&self, other: &Self) -> bool {
        self.inner.as_slice() != other.inner.as_slice()
    }

    fn __repr__(&self) -> String {
        let elems: Vec<String> = self.inner.as_slice().iter().map(|t| format!("{t:?}")).collect();
        format!("Vt.TokenArray([{}])", elems.join(", "))
    }

    fn __str__(&self) -> String {
        let elems: Vec<String> = self.inner.as_slice().iter().map(|t| t.to_string()).collect();
        format!("[{}]", elems.join(", "))
    }
}

