// ============================================================================
// Matrix4 arrays — stored as [[f64;4];4] / [[f32;4];4] row-major (matches usd_gf)
// ============================================================================

/// Convert Matrix4d to a flat 16-element Python-friendly tuple.
fn mat4d_to_flat(m: &usd_gf::Matrix4d) -> Vec<f64> {
    let a = m.to_array();
    a.iter().flat_map(|row| row.iter().copied()).collect()
}

/// Build Matrix4d from flat 16-element slice (row-major).
fn flat_to_mat4d(flat: &[f64]) -> Option<usd_gf::Matrix4d> {
    if flat.len() != 16 {
        return None;
    }
    let data = [
        [flat[0], flat[1], flat[2], flat[3]],
        [flat[4], flat[5], flat[6], flat[7]],
        [flat[8], flat[9], flat[10], flat[11]],
        [flat[12], flat[13], flat[14], flat[15]],
    ];
    Some(usd_gf::Matrix4d::from_array(data))
}

/// Convert Matrix4f to a flat 16-element Python-friendly tuple.
fn mat4f_to_flat(m: &usd_gf::Matrix4f) -> Vec<f32> {
    let a = m.to_array();
    a.iter().flat_map(|row| row.iter().copied()).collect()
}

/// Build Matrix4f from flat 16-element slice (row-major).
fn flat_to_mat4f(flat: &[f32]) -> Option<usd_gf::Matrix4f> {
    if flat.len() != 16 {
        return None;
    }
    let data = [
        [flat[0], flat[1], flat[2], flat[3]],
        [flat[4], flat[5], flat[6], flat[7]],
        [flat[8], flat[9], flat[10], flat[11]],
        [flat[12], flat[13], flat[14], flat[15]],
    ];
    Some(usd_gf::Matrix4f::from_array(data))
}

#[pyclass(name = "Matrix4dArray", module = "pxr.Vt")]
#[derive(Clone)]
pub struct PyMatrix4dArray {
    inner: Array<usd_gf::Matrix4d>,
}

#[pymethods]
impl PyMatrix4dArray {
    /// Construct empty, sized (identity fill), or from list of flat [f64;16].
    #[new]
    #[pyo3(signature = (arg = None))]
    fn new(arg: Option<&Bound<'_, PyAny>>) -> PyResult<Self> {
        let Some(obj) = arg else {
            return Ok(Self { inner: Array::new() });
        };
        if let Ok(n) = obj.extract::<usize>() {
            return Ok(Self {
                inner: Array::from_elem(usd_gf::Matrix4d::identity(), n),
            });
        }
        // Accept list of flat Vec<f64> (16 elements each, row-major)
        let items: Vec<Vec<f64>> = obj
            .extract()
            .map_err(|_| PyValueError::new_err("expected int size or list of 16-element float lists"))?;
        let mats: Vec<usd_gf::Matrix4d> = items
            .iter()
            .map(|flat| flat_to_mat4d(flat).ok_or_else(|| {
                PyValueError::new_err("each Matrix4d must be 16 floats")
            }))
            .collect::<PyResult<Vec<_>>>()?;
        Ok(Self { inner: Array::from(mats) })
    }

    fn __len__(&self) -> usize { self.inner.len() }

    fn __getitem__(&self, py: Python<'_>, key: &Bound<'_, PyAny>) -> PyResult<PyObject> {
        if let Ok(i) = key.extract::<isize>() {
            let idx = norm_idx(i, self.inner.len())?;
            let flat = mat4d_to_flat(&self.inner.as_slice()[idx]);
            Ok(flat.into_py(py))
        } else {
            Err(PyTypeError::new_err("index must be int"))
        }
    }

    fn __setitem__(&mut self, key: &Bound<'_, PyAny>, value: &Bound<'_, PyAny>) -> PyResult<()> {
        if let Ok(i) = key.extract::<isize>() {
            let idx = norm_idx(i, self.inner.len())?;
            let flat: Vec<f64> = value.extract()?;
            let m = flat_to_mat4d(&flat)
                .ok_or_else(|| PyValueError::new_err("Matrix4d requires 16 floats"))?;
            self.inner.make_unique();
            self.inner.as_mut_slice()[idx] = m;
            Ok(())
        } else {
            Err(PyTypeError::new_err("index must be int"))
        }
    }

    fn __iter__(slf: PyRef<'_, Self>) -> PyResult<Py<VtStringIter>> {
        let data: Vec<String> = slf.inner.as_slice()
            .iter()
            .map(|m| format!("{:?}", mat4d_to_flat(m)))
            .collect();
        Py::new(slf.py(), VtStringIter { data, pos: 0 })
    }

    fn __eq__(&self, other: &Self) -> bool {
        self.inner.as_slice() == other.inner.as_slice()
    }

    fn __ne__(&self, other: &Self) -> bool {
        self.inner.as_slice() != other.inner.as_slice()
    }

    fn __repr__(&self) -> String {
        format!("Vt.Matrix4dArray([{} items])", self.inner.len())
    }

    fn __str__(&self) -> String {
        format!("[{} Matrix4d]", self.inner.len())
    }
}

