// ============================================================================
// VtDictionary ↔ Python dict
// ============================================================================

/// Converts a Rust `Dictionary` to a Python `dict` recursively.
///
/// String keys are preserved; `Value` payloads are converted to the closest
/// Python type.  Nested dictionaries become nested dicts.
pub fn dict_to_py(py: Python<'_>, d: &Dictionary) -> PyResult<PyObject> {
    let dict = PyDict::new(py);
    for (k, v) in d.iter() {
        let py_val = value_to_py(py, v)?;
        dict.set_item(k, py_val)?;
    }
    Ok(dict.into())
}

/// Converts a Python object to a `Value`.
///
/// Supports: `None`, `bool`, `int`, `float`, `str`, `dict` (→ `Dictionary`).
pub fn py_to_value(obj: &Bound<'_, PyAny>) -> PyResult<Value> {
    if obj.is_none() {
        return Ok(Value::empty());
    }
    if let Ok(b) = obj.extract::<bool>() {
        return Ok(Value::new(b));
    }
    if let Ok(i) = obj.extract::<i64>() {
        if i >= i64::from(i32::MIN) && i <= i64::from(i32::MAX) {
            return Ok(Value::new(i as i32));
        }
        return Ok(Value::new(i));
    }
    if let Ok(f) = obj.extract::<f64>() {
        return Ok(Value::from_f64(f));
    }
    if let Ok(s) = obj.extract::<String>() {
        return Ok(Value::new(s));
    }
    if let Ok(d) = obj.downcast::<PyDict>() {
        let dict = py_dict_to_dict(d)?;
        return Ok(Value::from_dictionary(dict.to_hash_map()));
    }
    // Unknown Python object → empty value (safe fallback)
    Ok(Value::empty())
}

/// Converts a Python `dict` to a `Dictionary`.
fn py_dict_to_dict(d: &Bound<'_, PyDict>) -> PyResult<Dictionary> {
    let mut dict = Dictionary::new();
    for (k, v) in d.iter() {
        let key: String = k
            .extract()
            .map_err(|_| PyTypeError::new_err("VtDictionary keys must be strings"))?;
        let val = py_to_value(&v)?;
        dict.insert_value(key, val);
    }
    Ok(dict)
}

/// Renders a `Value` as a Python object.
fn value_to_py(py: Python<'_>, v: &Value) -> PyResult<PyObject> {
    if v.is_empty() {
        return Ok(py.None());
    }
    if let Some(b) = v.get::<bool>() {
        return Ok(b.into_py(py));
    }
    if let Some(i) = v.get::<i32>() {
        return Ok(i.into_py(py));
    }
    if let Some(i) = v.get::<i64>() {
        return Ok(i.into_py(py));
    }
    if let Some(u) = v.get::<u64>() {
        return Ok(u.into_py(py));
    }
    if let Some(x) = v.get::<f64>() {
        return Ok(x.into_py(py));
    }
    if let Some(x) = v.get::<f32>() {
        return Ok(((*x) as f64).into_py(py));
    }
    if let Some(s) = v.get::<String>() {
        return Ok(s.into_py(py));
    }
    if let Some(t) = v.get::<usd_tf::Token>() {
        return Ok(t.to_string().into_py(py));
    }
    if let Some(dict) = v.get::<usd_vt::Dictionary>() {
        return dict_to_py(py, dict);
    }
    // Fall back to None for unrecognized types
    Ok(py.None())
}

/// Python-facing `VtDictionary` class — thin wrapper that round-trips as a Python dict.
///
/// In C++ pxr, `VtDictionary` is typically passed as a plain `dict` in Python.
/// We provide the class for explicit construction and `__repr__` fidelity.
#[pyclass(name = "Dictionary", module = "pxr.Vt")]
#[derive(Clone, Default)]
pub struct PyDictionary {
    inner: Dictionary,
}

#[pymethods]
impl PyDictionary {
    #[new]
    #[pyo3(signature = (d = None))]
    fn new(d: Option<&Bound<'_, PyDict>>) -> PyResult<Self> {
        let inner = match d {
            Some(py_dict) => py_dict_to_dict(py_dict)?,
            None => Dictionary::new(),
        };
        Ok(Self { inner })
    }

    /// Convert to a plain Python `dict`.
    #[pyo3(name = "AsDict")]
    fn as_dict(&self, py: Python<'_>) -> PyResult<PyObject> {
        dict_to_py(py, &self.inner)
    }

    fn __len__(&self) -> usize { self.inner.len() }

    fn __repr__(&self, py: Python<'_>) -> PyResult<String> {
        let d = dict_to_py(py, &self.inner)?;
        Ok(format!("Vt.Dictionary({})", d.bind(py)))
    }

    fn __str__(&self, py: Python<'_>) -> PyResult<String> {
        let d = dict_to_py(py, &self.inner)?;
        Ok(format!("{}", d.bind(py)))
    }

    fn __getitem__(&self, py: Python<'_>, key: &str) -> PyResult<PyObject> {
        self.inner
            .get(key)
            .ok_or_else(|| PyKeyError::new_err(key.to_owned()))
            .and_then(|v| value_to_py(py, v))
    }

    fn __setitem__(&mut self, key: &str, value: &Bound<'_, PyAny>) -> PyResult<()> {
        let v = py_to_value(value)?;
        self.inner.insert_value(key.to_owned(), v);
        Ok(())
    }

    fn __contains__(&self, key: &str) -> bool {
        self.inner.contains_key(key)
    }

    fn __eq__(&self, other: &Self) -> bool {
        self.inner == other.inner
    }

    fn __ne__(&self, other: &Self) -> bool {
        self.inner != other.inner
    }

    fn keys(&self) -> Vec<String> {
        self.inner.keys().map(|k| k.to_owned()).collect()
    }
}

use pyo3::exceptions::PyKeyError;

// ============================================================================
// Module registration
// ============================================================================

/// Register all `pxr.Vt` classes into the submodule.
pub fn register(py: Python<'_>, m: &Bound<'_, PyModule>) -> PyResult<()> {
    let _ = py;

    // Value / _ValueWrapper
    m.add_class::<PyValue>()?;

    // Dictionary
    m.add_class::<PyDictionary>()?;

    // Scalar arrays
    m.add_class::<PyBoolArray>()?;
    m.add_class::<PyUCharArray>()?;
    m.add_class::<PyShortArray>()?;
    m.add_class::<PyUShortArray>()?;
    m.add_class::<PyIntArray>()?;
    m.add_class::<PyUIntArray>()?;
    m.add_class::<PyInt64Array>()?;
    m.add_class::<PyUInt64Array>()?;
    m.add_class::<PyFloatArray>()?;
    m.add_class::<PyDoubleArray>()?;
    m.add_class::<PyHalfArray>()?;

    // String / Token arrays
    m.add_class::<PyStringArray>()?;
    m.add_class::<PyTokenArray>()?;

    // Vec arrays
    m.add_class::<PyVec2fArray>()?;
    m.add_class::<PyVec3fArray>()?;
    m.add_class::<PyVec4fArray>()?;
    m.add_class::<PyVec2dArray>()?;
    m.add_class::<PyVec3dArray>()?;
    m.add_class::<PyVec4dArray>()?;
    m.add_class::<PyVec2iArray>()?;
    m.add_class::<PyVec3iArray>()?;
    m.add_class::<PyVec4iArray>()?;

    // Matrix arrays
    m.add_class::<PyMatrix4dArray>()?;
    m.add_class::<PyMatrix4fArray>()?;

    // Scalar iterators (concrete per-type, no generics allowed in PyO3)
    m.add_class::<VtBoolIter>()?;
    m.add_class::<VtI32Iter>()?;
    m.add_class::<VtU32Iter>()?;
    m.add_class::<VtI64Iter>()?;
    m.add_class::<VtU64Iter>()?;
    m.add_class::<VtI8Iter>()?;
    m.add_class::<VtU8Iter>()?;
    m.add_class::<VtI16Iter>()?;
    m.add_class::<VtU16Iter>()?;
    m.add_class::<VtF32Iter>()?;
    m.add_class::<VtF64Iter>()?;
    m.add_class::<VtStringIter>()?;

    Ok(())
}
